735#XW|        tokensBefore,
736#BP|        tokensAfter,
737#HV|        error: `context overflow recovery exhausted all strategies (prune → compact → aggressive-compact → truncate). tokensBefore=${tokensBefore}, tokensAfter=${tokensAfter}, contextLimit=${contextLimit}`,
